head.script:
var getOptanonWrapper=window.OptanonWrapper;
window.OptanonWrapper = function() {
if( typeof getOptanonWrapper === 'function' ) getOptanonWrapper();
var adobeScript = document.createElement('script');
adobeScript.type = 'text/javascript';
adobeScript.src = "https://assets.adobedtm.com/62b169e963f5/daaba6c90a78/launch-8b7b6db2239b.min.js";
adobeScript.id = 'adobe-dtm-script-0';

adobeScript.async = true;

const existingAdobeScript = document.getElementById('adobe-dtm-script-0');
if (existingAdobeScript) {
      console.log('existing Adobe DTM script element is in the document');
      return;
      }
if (document && document?.head && adobeScript) {
  document.head.appendChild(adobeScript);
}else{
  console.error('Unable to append Adobe DTM script to the document head');
}
} ;         
//# sourceURL=adobe-dtm-wrapper-inline.js
